// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
// NOTE RAJ - this will call an event to launch a process to recurse the tree and save the template.
if(typeof window == 'undefined'){
	saveTemplate();
	// STRY0072078 - change "My Template" to "Personal Template"
	gs.addInfoMessage("'"+ current.task_name + "'" + ' has been saved as a Template. You can find it under' + '<a href="../discovertaskerportal?id=discovertasker_processtemplatelist&table=x_153465_discovert_discover_routing_template&filter=process_level%3Dglobal_process%5ENQprocess_level%3Dou_process%5ENQprocess_level%3Dmy_process%5Eprocess_ownerDYNAMIC90d1921e5f510100a9ad2572f2b477fe%5EEQ"> Personal Templates </a>');
}
var x = new uiConditionCheck().saveTaskAsProcessTemplate(current);
//AA - STRY0037846 - bug
checkIfNameExists(current.short_description);
function checkIfNameExists(name){
	var templateName = name;

	var gr = new GlideAggregate('x_153465_discovert_discover_routing_template');
	gr.addQuery('template_name', templateName);
	gr.query();

	if(gr.next()){
		// STRY0072083
		gs.addInfoMessage("There is already a Template with that name.  Saving Template as a copy.");
	}

	return templateName;
}

function saveTemplate()
{
	// start the process of creating a new process definition
	gs.eventQueue('x_153465_discovert.Save_as_Template', current, 'Save as Template',  gs.getUserID());

}
